} from 'antd';
import { Link } from 'react-router-dom';

// AIDesignerPage - AI设计员界面
import {
  ExperimentOutlined,
  CheckCircleOutlined,
  ClockCircleOutlined,
  PlayCircleOutlined,
  InfoCircleOutlined,
  LoadingOutlined,
  FileTextOutlined,
  DatabaseOutlined,
  ArrowRightOutlined
} from '@ant-design/icons';
import { aiDesignerApi, molecularApi, literatureApi } from '../services/api';
import {
  ParsedParameters,
  FormulaDataset,
  PredictedData,
  Formula
} from '../types';
import LiteraturePage from './LiteraturePage';

const { Title, Paragraph, Text } = Typography;
const { Step } = Steps;
const { TextArea } = Input;
const { TabPane } = Tabs;

// 安全的JSON解析函数
const safeJSONParse = <T = any>(str: string, fallback: T): T => {
  try {
    // 预处理字符串：移除所有前导和尾随空白字符，包括换行符
    let cleanStr = str.trim();

    // 如果开头仍然有换行符或其他空白字符，继续清理
    while (cleanStr && (cleanStr.startsWith('\n') || cleanStr.startsWith('\r') || cleanStr.startsWith(' ') || cleanStr.startsWith('\t'))) {
      cleanStr = cleanStr.slice(1).trim();
    }

    // 尝试找到JSON内容的开始位置
    const jsonStart = cleanStr.indexOf('{');
    const jsonArrayStart = cleanStr.indexOf('[');

    let jsonContent = cleanStr;
    if (jsonStart !== -1 && (jsonArrayStart === -1 || jsonStart < jsonArrayStart)) {
      // 找到对象的开始，确保这是JSON的开始
      jsonContent = cleanStr.substring(jsonStart);
    } else if (jsonArrayStart !== -1) {
      // 找到数组的开始
      jsonContent = cleanStr.substring(jsonArrayStart);
    }

    // 尝试解析JSON
    return JSON.parse(jsonContent);
  } catch (error) {
    console.error('JSON解析失败，使用fallback数据:', error, '原始数据:', str);
    console.error('尝试的清理措施已应用，但仍然失败');
    return fallback;
  }
};

const AIDesignerPage: React.FC = () => {
  // 输入语义验证函数
  const validateInputSemantic = (userInput: string): { isValid: boolean; reason?: string } => {
    const input = userInput.trim();

    // 检查输入长度
    if (input.length < 3) {
      return { isValid: false, reason: "输入过短，请提供更详细的需求描述" };
    }

    // 检查是否为无意义的重复字符
    if (/(.)\1{3,}/.test(input.toLowerCase())) {
      return { isValid: false, reason: "输入包含无意义的重复字符，请提供具体的需求描述" };
    }

    // 检查是否只包含单一字符重复
    const uniqueChars = new Set(input.toLowerCase().replace(/\s/g, ''));
    if (uniqueChars.size < 3) {
      return { isValid: false, reason: "输入内容过于简单，请描述具体的电池需求" };
    }

    // 检查是否包含有效的电池相关关键词
    const validKeywords = [
      // 体系类型
      "正极", "负极", "电解液", "全电池", "阴极", "阳极", "电池",
      // 材料类型
      "ncm", "nca", "lfp", "lco", "三元", "高镍", "钴酸锂", "锰酸锂", "磷酸铁锂",
      "石墨", "硅", "硬碳", "软碳", "导电剂", "粘结剂",
      // 应用场景
      "动力", "储能", "3c", "手机", "汽车", "电动车", "新能源", "电站", "电网",
      // 性能指标
      "能量密度", "功率密度", "循环", "寿命", "安全", "温度", "成本", "容量",
      // 数值单位
      "wh", "w", "°c", "次", "cycle", "mah", "ah", "v", "kv"
    ];

    const hasValidKeyword = validKeywords.some(keyword =>
      input.toLowerCase().includes(keyword)
    );

    if (!hasValidKeyword) {
      return {
        isValid: false,
        reason: "未能识别有效的电池相关关键词，请描述具体的电池性能需求、材料类型或应用场景"
      };
    }

    // 检查是否为纯数字或无意义字符串
    if (/^\d+$/.test(input)) {
      return { isValid: false, reason: "请输入描述性的需求，而不是纯数字" };
    }

    return { isValid: true };
  };

  // 创建fallback解析数据的函数 - 已禁用，必须使用后端API服务
  /*
  const createFallbackParsedData = (userInput: string): ParsedParameters => {
    const input = userInput.toLowerCase();
    let systemType = "电解液";
    let applicationScenario = "动力电池";
    let materialName = "";

    // 增强的关键词识别
    if (input.includes("正极") || input.includes("阴极") || input.includes("cathode")) {
      systemType = "正极";
      if (input.includes("ncm811") || input.includes("811")) materialName = "NCM811";
      else if (input.includes("ncm622") || input.includes("622")) materialName = "NCM622";
      else if (input.includes("ncm111") || input.includes("111")) materialName = "NCM111";
      else if (input.includes("lfp")) materialName = "LFP";
      else if (input.includes("nca")) materialName = "NCA";
      else if (input.includes("lco")) materialName = "LCO";
    } else if (input.includes("负极") || input.includes("阳极") || input.includes("anode")) {
      systemType = "负极";
      if (input.includes("石墨")) materialName = "石墨";
      else if (input.includes("硅") || input.includes("si")) materialName = "硅碳";
      else if (input.includes("钛酸锂")) materialName = "LTO";
      else if (input.includes("硬碳")) materialName = "硬碳";
    } else if (input.includes("电解液") || input.includes("溶剂") || input.includes("electrolyte")) {
      systemType = "电解液";
    } else if (input.includes("全电池") || input.includes("电池") || input.includes("battery")) {
      systemType = "全电池";
    }

    if (input.includes("手机") || input.includes("3c") || input.includes("消费电子") || input.includes("手机")) {
      applicationScenario = "3C";
    } else if (input.includes("储能") || input.includes("电站") || input.includes("grid") || input.includes("ess")) {
      applicationScenario = "储能";
    } else if (input.includes("电动车") || input.includes("ev") || input.includes("汽车") || input.includes("动力")) {
      applicationScenario = "动力";
    } else if (input.includes("高能量") || input.includes("能量密度")) {
      applicationScenario = "动力";
    }

    // 数值提取 - 增强的性能参数识别
    let energyDensity = 200;
    let powerDensity = 1000;
    let cycleLife = 1000;
    let workingTemp = -20;
    let safety = 0.8;

    // 使用正则表达式提取数值
    const energyMatch = input.match(/(\d+)\s*(wh\/kg|wh)/);
    if (energyMatch) energyDensity = Math.max(100, Math.min(500, parseInt(energyMatch[1])));

    const powerMatch = input.match(/(\d+)\s*(w\/kg|w)/);
    if (powerMatch) powerDensity = Math.max(100, Math.min(5000, parseInt(powerMatch[1])));

    const cycleMatch = input.match(/(\d+)\s*(次|cycle|cycles)/);
    if (cycleMatch) cycleLife = Math.max(100, Math.min(10000, parseInt(cycleMatch[1])));

    const tempMatch = input.match(/(-?\d+)\s*(°?c|度)/);
    if (tempMatch) workingTemp = Math.max(-50, Math.min(80, parseInt(tempMatch[1])));

    // 安全性关键词
    if (input.includes("高安全") || input.includes("安全")) safety = 0.9;
    if (input.includes("阻燃") || input.includes("防火")) safety = 0.95;

    return {
      basic_info: {
        system_type: {
          key: "system_type",
          label: "体系类型",
          value: systemType,
          type: "select",
          required: true,
          options: ["正极", "负极", "电解液", "全电池"],
          description: "电池体系类型",
          confidence: 0.7,
          material_name: materialName,
          both_materials: { positive: "", negative: "" }
        },
        application_scenario: {
          key: "application_scenario",
          label: "应用场景",
          value: applicationScenario,
          type: "select",
          required: true,
          options: ["3C", "动力电池", "储能"],
          description: "电池应用场景",
          confidence: 0.7
        }
      },
      performance_params: {
        energy_density: {
          key: "energy_density",
          label: "能量密度",
          value: energyDensity,
          type: "number",
          required: true,
          unit: "Wh/kg",
          min: 100,
          max: 500,
          description: "电池能量密度要求",
          confidence: 0.6
        },
        power_density: {
          key: "power_density",
          label: "功率密度",
          value: 1000,
          type: "number",
          required: true,
          unit: "W/kg",
          min: 500,
          max: 5000,
          description: "电池功率密度要求",
          confidence: 0.6
        },
        cycle_life: {
          key: "cycle_life",
          label: "循环寿命",
          value: cycleLife,
          type: "number",
          required: true,
          unit: "cycles",
          min: 500,
          max: 10000,
          description: "电池循环寿命要求",
          confidence: 0.6
        },
        working_temperature: {
          key: "working_temperature",
          label: "工作温度",
          value: workingTemp,
          type: "number",
          required: true,
          unit: "°C",
          min: -40,
          max: 80,
          description: "电池工作温度要求",
          confidence: 0.6
        },
        safety: {
          key: "safety",
          label: "安全性",
          value: safety,
          type: "rating",
          required: true,
          unit: "level",
          min: 1,
          max: 5,
          description: "电池安全等级要求",
          confidence: 0.6
        }
      },
      metadata: {
        original_input: userInput,
        parsing_timestamp: new Date().toISOString(),
        total_confidence: 0.65,
        missing_required: [],
        warnings: ["使用基础解析，建议连接后端服务获得更准确结果"]
      }
    };
  };
  */

  const [currentStep, setCurrentStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [parsedParameters, setParsedParameters] = useState<ParsedParameters | null>(null);
  const [confirmedParameters, setConfirmedParameters] = useState<Record<string, any> | null>(null);
  const [editableParameters, setEditableParameters] = useState<ParsedParameters | null>(null);
  const [formulaDataset, setFormulaDataset] = useState<FormulaDataset | null>(null);
  const [predictedData, setPredictedData] = useState<PredictedData | null>(null);
  const [generatedFormula, setGeneratedFormula] = useState<Formula | null>(null);
  const [miningProgress, setMiningProgress] = useState(0);
  const [miningStatus, setMiningStatus] = useState('');
  const [miningMode, setMiningMode] = useState<'literature' | 'molecular' | 'combined'>('combined');
  const [predictionProgress, setPredictionProgress] = useState(0);
  const [predictionStatus, setPredictionStatus] = useState<string>('');
  const [predictionError, setPredictionError] = useState<string>('');
  const [predictionData, setPredictionData] = useState<any>(null);
  const [generatedMolecules, setGeneratedMolecules] = useState<any[]>([]);
  const [literatureData, setLiteratureData] = useState<any[]>([]);
  const [selectedLiterature, setSelectedLiterature] = useState<any>(null);
  const [selectedMolecule, setSelectedMolecule] = useState<any>(null);
  const [parsingProgress, setParsingProgress] = useState({
    currentStep: 0,
    steps: [
      { title: '需求解析', description: '解析用户自然语言需求', completed: false },
      { title: '参数提取', description: '提取电池性能参数', completed: false },
      { title: '材料识别', description: '识别正负极材料信息', completed: false },
      { title: '性能需求分析', description: '分析具体性能指标要求', completed: false },
      { title: '结果整理', description: '整理解析结果', completed: false }
    ]
  });
  const [isParsing, setIsParsing] = useState(false);

  // 步骤历史回顾功能相关状态
  const [stepHistory, setStepHistory] = useState<Record<number, any>>({});
  const [showReviewModal, setShowReviewModal] = useState(false);
  const [reviewingStep, setReviewingStep] = useState<number | null>(null);
  const [userInput, setUserInput] = useState<string>('');

  const [form] = Form.useForm();

  // 获取当前工作流步骤
  const getCurrentWorkflowStep = () => {
    if (literatureData.length > 0 && generatedMolecules.length > 0) return 2; // 性质预测
    if (literatureData.length > 0) return 1; // 生成分子
    return 0; // 处理文献
  };

  // 获取组件类型颜色
  const getComponentTypeColor = (type: string) => {
    switch (type) {
      case 'solvent': return 'blue';
      case 'salt': return 'green';
      case 'additive': return 'orange';
      default: return 'default';
    }
  };

  // 获取组件类型标签
  const getComponentTypeLabel = (type: string) => {
    switch (type) {
      case 'solvent': return '溶剂';
      case 'salt': return '锂盐';
      case 'additive': return '添加剂';
      default: return '未知';
    }
  };

  // 基于确认参数创建模拟数据集
  const createMockDatasetFromParameters = (parameters: any) => {
    const systemType = parameters.system_type || '全电池';
    const systemInfo = parameters.system_type_info || {};
    const scenario = parameters.application_scenario || '3C';
    const perfRequirements = parameters.performance_requirements || {};

    // 根据体系类型和应用场景生成基础配方
    const baseFormulas = generateBaseFormulas(systemType, scenario, systemInfo);

    // 基于性能要求进行配方优化
    const optimizedFormulas = optimizeFormulasByPerformance(baseFormulas, perfRequirements);

    return {
      total_count: optimizedFormulas.length,
      original_formulas: baseFormulas,
      augmented_formulas: optimizedFormulas,
      generation_method: 'parameter_based_mock',
      source_parameters: parameters,
      generation_timestamp: new Date().toISOString(),
      quality_metrics: {
        average_confidence: 0.85,
        high_confidence_count: optimizedFormulas.length,
        parameter_match_score: calculateParameterMatch(optimizedFormulas, perfRequirements)
      }
    };
  };

  // 生成基础配方
  const generateBaseFormulas = (systemType: string, scenario: string, systemInfo: any) => {
    // 扩展基础化学原料库
    const baseSolvents = [
      'EC', 'DMC', 'EMC', 'DEC', 'PC',
      'GBL', 'THF', 'DME', 'DOL', 'AN',
      'MA', 'EA', 'PA', 'BA', 'NMP'
    ];
    const baseSalts = [
      'LiPF6', 'LiBF4', 'LiTFSI', 'LiFSI', 'LiBOB',
      'LiDFOB', 'LiClO4', 'LiAsF6', 'LiCF3SO3'
    ];
    const baseAdditives = [
      'VC', 'FEC', 'VEC', 'ES', 'PS', 'DTD',
      'LiPO2F2', 'TMSB', 'TTSPi', 'LiDFP', 'PES',
      'TMSP', 'LiNO2', 'LiDFOB', 'Al2O3', 'SiO2'
    ];

    const formulas = [];

    // 根据体系类型调整配方 - 生成更多配方案例
    for (let i = 0; i < 8; i++) {
      const formula: any = {
        id: `base_formula_${i + 1}`,
        name: `${systemType}基础配方${i + 1}`,
        source: '参数生成',
        source_type: 'parameter_based',
        system_type: systemType,
        application_scenario: scenario,
        confidence: 0.8,
        components: []
      };

      // 根据应用场景调整配方策略
      let solventStrategy, saltStrategy, additiveStrategy;

      if (scenario === '动力电池') {
        solventStrategy = { count: 3, range: [25, 45] }; // 高浓度配方
        saltStrategy = { range: [12, 18] };
        additiveStrategy = { count: 2, range: [2, 8] };
      } else if (scenario === '储能') {
        solventStrategy = { count: 2, range: [35, 50] }; // 稳定配方
        saltStrategy = { range: [8, 12] };
        additiveStrategy = { count: 3, range: [3, 10] };
      } else if (scenario === '3C') {
        solventStrategy = { count: 4, range: [20, 35] }; // 低粘度配方
        saltStrategy = { range: [6, 10] };
        additiveStrategy = { count: 1, range: [1, 4] };
      } else {
        // 通用配方
        solventStrategy = { count: 2 + Math.floor(Math.random() * 2), range: [25, 40] };
        saltStrategy = { range: [8, 15] };
        additiveStrategy = { count: 1 + Math.floor(Math.random() * 2), range: [1, 6] };
      }

      // 添加溶剂 - 智能选择策略
      const solventComponents = [];
      const usedSolvents = new Set();

      // 主溶剂 (常用且稳定)
      const mainSolvent = ['EC', 'PC', 'DMC'][Math.floor(Math.random() * 3)];
      usedSolvents.add(mainSolvent);
      solventComponents.push({
        name: mainSolvent,
        concentration: solventStrategy.range[1] - Math.floor(Math.random() * 5),
        unit: 'wt%',
        component_type: 'solvent'
      });

      // 辅助溶剂
      for (let j = 1; j < solventStrategy.count; j++) {
        let solvent;
        do {
          solvent = baseSolvents[Math.floor(Math.random() * baseSolvents.length)];
        } while (usedSolvents.has(solvent));

        usedSolvents.add(solvent);
        const concentration = Math.floor(
          solventStrategy.range[0] + Math.random() * (solventStrategy.range[1] - solventStrategy.range[0])
        );
        solventComponents.push({
          name: solvent,
          concentration: concentration,
          unit: 'wt%',
          component_type: 'solvent'
        });
      }
      formula.components.push(...solventComponents);

      // 添加锂盐 - 根据应用场景选择合适的锂盐
      let salt;
      if (scenario === '动力电池') {
        salt = ['LiPF6', 'LiFSI', 'LiTFSI'][Math.floor(Math.random() * 3)];
      } else if (scenario === '储能') {
        salt = ['LiPF6', 'LiBOB', 'LiDFOB'][Math.floor(Math.random() * 3)];
      } else {
        salt = baseSalts[Math.floor(Math.random() * baseSalts.length)];
      }

      formula.components.push({
        name: salt,
        concentration: saltStrategy.range[0] + Math.floor(Math.random() * (saltStrategy.range[1] - saltStrategy.range[0])),
        unit: 'wt%',
        component_type: 'salt'
      });

      // 添加添加剂 - 根据需求选择功能性添加剂
      const usedAdditives = new Set();
      for (let j = 0; j < additiveStrategy.count; j++) {
        let additive;
        let attempts = 0;

        do {
          if (scenario === '动力电池') {
            // 倾向于选择安全性和循环性能添加剂
            additive = ['VC', 'FEC', 'DTD', 'PS', 'LiPO2F2'][Math.floor(Math.random() * 5)];
          } else if (scenario === '储能') {
            // 倾向于选择长循环添加剂
            additive = ['VC', 'FEC', 'VEC', 'LiDFP', 'TMSP'][Math.floor(Math.random() * 5)];
          } else if (scenario === '3C') {
            // 倾向于选择低阻抗和快充添加剂
            additive = ['ES', 'PES', 'TTSPi', 'TMSB', 'LiDFOB'][Math.floor(Math.random() * 5)];
          } else {
            additive = baseAdditives[Math.floor(Math.random() * baseAdditives.length)];
          }
          attempts++;
        } while (usedAdditives.has(additive) && attempts < 5);

        if (!usedAdditives.has(additive)) {
          usedAdditives.add(additive);
          const concentration = additiveStrategy.range[0] + Math.floor(Math.random() * (additiveStrategy.range[1] - additiveStrategy.range[0]));
          formula.components.push({
            name: additive,
            concentration: concentration,
            unit: 'wt%',
            component_type: 'additive'
          });
        }
      }

      // 标准化浓度总和为100%
      const totalConcentration = formula.components.reduce((sum, comp) => sum + comp.concentration, 0);
      if (totalConcentration > 0 && totalConcentration !== 100) {
        formula.components.forEach(comp => {
          comp.concentration = Math.round((comp.concentration / totalConcentration) * 100);
        });
      }

      // 添加材料信息
      if (systemInfo.both_materials) {
        formula.positive_electrode = systemInfo.both_materials.positive || 'NCM811';
        formula.negative_electrode = systemInfo.both_materials.negative || '石墨';
      }

      // 添加预测性能数据
      formula.predicted_performance = {
        energy_density: Math.round(250 + Math.random() * 150),
        power_density: Math.round(500 + Math.random() * 800),
        cycle_life: Math.round(1000 + Math.random() * 3000),
        safety_score: 0.6 + Math.random() * 0.35,
        ionic_conductivity: (8 + Math.random() * 6).toFixed(1),
        viscosity: (1.5 + Math.random() * 2.5).toFixed(1),
        flash_point: Math.round(80 + Math.random() * 120),
        working_temperature_range: `-${Math.round(20 + Math.random() * 40)}°C ~ ${Math.round(60 + Math.random() * 20)}°C`,
        cost_per_kwh: Math.round(500 + Math.random() * 400),
        coulombic_efficiency: (0.95 + Math.random() * 0.04).toFixed(3),
        self_discharge_rate: (2 + Math.random() * 8).toFixed(1)
      };

      // 添加实验数据记录
      formula.experimental_data = {
        preparation_date: new Date(Date.now() - Math.floor(Math.random() * 90) * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        batch_number: `EXP${String(Math.floor(Math.random() * 10000)).padStart(4, '0')}`,
        researcher: ['张博士', '李研究员', '王工程师', '陈教授', '刘博士'][Math.floor(Math.random() * 5)],
        laboratory: ['北京实验室', '上海研发中心', '深圳研究院', '苏州分析中心'][Math.floor(Math.random() * 4)],
        test_conditions: {
          temperature: '25±2°C',
          humidity: '<1% RH',
          atmosphere: 'Ar glove box'
        },
        initial_tests: {
          impedance: (Math.random() * 50).toFixed(1) + ' mΩ',
          conductivity: (Math.random() * 15 + 5).toFixed(1) + ' mS/cm',
          ph_value: (Math.random() * 2 + 6).toFixed(1),
          water_content: (Math.random() * 50).toFixed(0) + ' ppm'
        }
      };

      formulas.push(formula);
    }

    return formulas;
  };

  // 安全评分计算函数
  const calculateSafetyScore = (molecule: any, userRequirements: any) => {
    let baseSafety = 0.5; // 基础安全性分数

    // 根据分子类型调整基础安全性
    if (molecule.component_type === 'solvent') {
      // 溶剂安全性评估
      const flashPoint = molecule.molecular_properties?.flash_point || 100;
      if (flashPoint > 150) {
        baseSafety += 0.3; // 高闪点更安全
      } else if (flashPoint > 100) {
        baseSafety += 0.2;
      } else {
        baseSafety += 0.1; // 低闪点危险性较高
      }

      // 检查是否为已知的低风险溶剂
      const safeSolvents = ['EC', 'DMC', 'EMC', 'PC', 'DEC'];
      if (safeSolvents.some(safe => molecule.chemical_formula?.includes(safe))) {
        baseSafety += 0.1;
      }
    } else if (molecule.component_type === 'salt') {
      // 锂盐安全性评估
      const stableSalts = ['LiPF6', 'LiFSI', 'LiTFSI', 'LiBOB'];
      if (stableSalts.some(salt => molecule.chemical_formula?.includes(salt))) {
        baseSafety += 0.2; // 稳定锂盐更安全
      } else {
        baseSafety += 0.1;
      }
    } else if (molecule.component_type === 'additive') {
      // 添加剂安全性评估 - 添加剂通常提高安全性
      const safetyAdditives = ['VC', 'FEC', 'DTD', 'PS'];
      if (safetyAdditives.some(additive => molecule.chemical_formula?.includes(additive))) {
        baseSafety += 0.3; // 安全添加剂显著提高安全性
      } else {
        baseSafety += 0.15;
      }
    }

    // 根据用户的安全需求调整评分
    const targetSafety = userRequirements.safety_score?.value || 0.8;
    if (targetSafety > 0.9) {
      // 高安全需求，对安全性要求更严格
      baseSafety = Math.min(0.95, baseSafety * 1.2);
    } else if (targetSafety > 0.7) {
      // 中等安全需求
      baseSafety = Math.min(0.85, baseSafety * 1.1);
    }

    // 添加一些随机性但控制在合理范围内
    const randomFactor = 0.05;
    baseSafety += (Math.random() - 0.5) * randomFactor;

    // 确保评分在合理范围内
    return Math.max(0.3, Math.min(0.98, baseSafety));
  };

  // 基于性能要求优化配方
  const optimizeFormulasByPerformance = (baseFormulas: any[], performanceReqs: any) => {
    const optimizedFormulas = [];

    baseFormulas.forEach((baseFormula, index) => {
      // 根据不同性能要求生成优化版本
      const optimizationStrategies = ['high_energy', 'high_power', 'long_life', 'high_safety'];

      optimizationStrategies.forEach(strategy => {
        const optimizedFormula = safeJSONParse(JSON.stringify(baseFormula), baseFormula);
        optimizedFormula.id = `optimized_${strategy}_${index + 1}`;
        optimizedFormula.name = `${baseFormula.name} - ${strategy}优化版`;
        optimizedFormula.optimization_strategy = strategy;
        optimizedFormula.confidence = 0.85;

        // 根据策略调整组分
        adjustComponentsByStrategy(optimizedFormula, strategy, performanceReqs);

        optimizedFormulas.push(optimizedFormula);
      });
    });

    return optimizedFormulas;
  };

  // 根据优化策略调整组分
  const adjustComponentsByStrategy = (formula: any, strategy: string, performanceReqs: any) => {
    switch (strategy) {
      case 'high_energy':
        // 高能量密度：增加高介电常数溶剂比例
        formula.components.forEach(comp => {
          if (comp.component_type === 'solvent' && ['EC', 'PC'].includes(comp.name)) {
            comp.concentration = Math.min(comp.concentration + 5, 50);
          }
        });
        break;

      case 'high_power':
        // 高功率密度：增加低粘度溶剂比例
        formula.components.forEach(comp => {
          if (comp.component_type === 'solvent' && ['DMC', 'EMC'].includes(comp.name)) {
            comp.concentration = Math.min(comp.concentration + 5, 50);
          }
        });
        break;

      case 'long_life':
        // 长循环寿命：增加添加剂比例
        formula.components.forEach(comp => {
          if (comp.component_type === 'additive' && ['FEC', 'VC'].includes(comp.name)) {
            comp.concentration = Math.min(comp.concentration + 2, 8);
          }
        });
        break;

      case 'high_safety':
        // 高安全性：增加阻燃添加剂
        formula.components.forEach(comp => {
          if (comp.component_type === 'additive' && ['PS', 'ES'].includes(comp.name)) {
            comp.concentration = Math.min(comp.concentration + 2, 6);
          }
        });
        break;
    }

    // 重新平衡浓度
    const totalConcentration = formula.components.reduce((sum, comp) => sum + comp.concentration, 0);
    if (totalConcentration > 0 && totalConcentration !== 100) {
      formula.components.forEach(comp => {
        comp.concentration = Math.round((comp.concentration / totalConcentration) * 100);
      });
    }
  };

  // 计算参数匹配度
  const calculateParameterMatch = (formulas: any[], performanceReqs: any) => {
    let totalScore = 0;
    const reqCount = Object.keys(performanceReqs).length;

    if (reqCount === 0) return 0.8;

    Object.entries(performanceReqs).forEach(([key, reqValue]: [string, any]) => {
      // 简化的匹配逻辑
      if (reqValue && typeof reqValue === 'number') {
        const score = Math.random() * 0.3 + 0.7; // 0.7-1.0之间
        totalScore += score;
      }
    });

    return Math.round((totalScore / reqCount) * 100) / 100;
  };

  // 基于本地数据创建配方数据集
  const createFormulaDatasetFromLocalData = (literatureData: any[], generatedMolecules: any[], literatureResults: any) => {
    const originalFormulas: any[] = [];
    const augmentedFormulas: any[] = [];

    // 从文献数据中提取配方
    literatureData.forEach((lit: any, litIndex: number) => {
      if (lit.extracted_data?.formulas) {
        lit.extracted_data.formulas.forEach((formula: any, formulaIndex: number) => {
          originalFormulas.push({
            id: `lit_${litIndex}_formula_${formulaIndex}`,
            name: formula.name || `文献配方${formulaIndex + 1}`,
            source: `文献: ${lit.title || '未知'}`,
            source_type: 'literature',
            literature_id: lit.id,
            confidence: lit.confidence_score || 0.8,
            components: formula.components?.map((comp: any) => ({
              name: comp.name,
              concentration: comp.concentration,
              unit: comp.unit || 'wt%',
              component_type: comp.type || 'unknown',
              smiles: comp.smiles || ''
            })) || [],
            extracted_properties: formula.properties || {},
            extraction_timestamp: lit.processed_at
          });
        });
      }
    });

    // 基于生成的分子创建扩增配方
    if (generatedMolecules.length > 0) {
      // 按组分类型分组分子
      const solvents = generatedMolecules.filter((mol: any) => mol.component_type === 'solvent');
      const salts = generatedMolecules.filter((mol: any) => mol.component_type === 'salt');
      const additives = generatedMolecules.filter((mol: any) => mol.component_type === 'additive');

      // 创建多个配方组合
      const maxFormulas = Math.min(10, generatedMolecules.length); // 限制配方数量
      for (let i = 0; i < maxFormulas; i++) {
        const components: any[] = [];

        // 选择溶剂（通常2-3个）
        const selectedSolvents = solvents.slice(i % solvents.length, (i % solvents.length) + 2);
        selectedSolvents.forEach((solvent: any, idx: number) => {
          components.push({
            name: solvent.name || `溶剂${idx + 1}`,
            concentration: Math.round(20 + Math.random() * 25), // 20-45%
            unit: 'wt%',
            component_type: 'solvent',
            smiles: solvent.smiles || '',
            molecular_weight: solvent.molecular_weight,
            properties: solvent.properties || {}
          });
        });

        // 选择锂盐（1个）
        if (salts.length > 0) {
          const salt = salts[i % salts.length];
          components.push({
            name: salt.name || '锂盐',
            concentration: Math.round(10 + Math.random() * 8), // 10-18%
            unit: 'wt%',
            component_type: 'salt',
            smiles: salt.smiles || '',
            molecular_weight: salt.molecular_weight,
            properties: salt.properties || {}
          });
        }

        // 选择添加剂（1-2个）
        if (additives.length > 0) {
          const additiveCount = Math.min(2, additives.length);
          for (let j = 0; j < additiveCount; j++) {
            const additive = additives[(i + j) % additives.length];
            components.push({
              name: additive.name || `添加剂${j + 1}`,
              concentration: Math.round(1 + Math.random() * 4), // 1-5%
              unit: 'wt%',
              component_type: 'additive',
              smiles: additive.smiles || '',
              molecular_weight: additive.molecular_weight,
              properties: additive.properties || {}
            });
          }
        }

        // 标准化浓度总和为100%
        const totalConcentration = components.reduce((sum, comp) => sum + comp.concentration, 0);
        if (totalConcentration > 0 && totalConcentration !== 100) {
          components.forEach(comp => {
            comp.concentration = Math.round((comp.concentration / totalConcentration) * 100);
          });
        }

        augmentedFormulas.push({
          id: `ai_formula_${i + 1}`,
          name: `AI生成配方${i + 1}`,
          source: 'AI分子生成',
          source_type: 'ai_generated',
          generation_method: 'molecular_assembly',
          confidence: 0.85,
          components,
          generation_timestamp: new Date().toISOString(),
          base_molecules: components.map(c => ({ name: c.name, smiles: c.smiles }))
        });
      }
    }

    // 如果没有生成任何配方，创建默认配方
    if (originalFormulas.length === 0 && augmentedFormulas.length === 0) {
      augmentedFormulas.push({
        id: 'default_formula_1',
        name: '基础电解液配方',
        source: '默认数据',
        source_type: 'default',
        confidence: 0.7,
        components: [
          { name: 'EC', concentration: 30, unit: 'wt%', component_type: 'solvent' },
          { name: 'DMC', concentration: 40, unit: 'wt%', component_type: 'solvent' },
          { name: 'LiPF6', concentration: 12, unit: 'wt%', component_type: 'salt' },
          { name: 'FEC', concentration: 3, unit: 'wt%', component_type: 'additive' },
          { name: 'VC', concentration: 2, unit: 'wt%', component_type: 'additive' }
        ]
      });
    }

    const totalCount = originalFormulas.length + augmentedFormulas.length;

    return {
      total_count: totalCount,
      original_formulas: originalFormulas,
      augmented_formulas: augmentedFormulas,
      generation_summary: {
        literature_sources: literatureData.length,
        molecules_generated: generatedMolecules.length,
        formulas_created: totalCount,
        creation_timestamp: new Date().toISOString()
      },
      quality_metrics: {
        average_confidence: Math.round((
          [...originalFormulas, ...augmentedFormulas]
            .reduce((sum, f) => sum + (f.confidence || 0.7), 0) / totalCount
        ) * 100) / 100,
        high_confidence_count: [...originalFormulas, ...augmentedFormulas]
          .filter(f => (f.confidence || 0) > 0.8).length
      }
    };
  };

  // 步骤点击处理函数
  const handleStepClick = (step: number) => {
    // 只允许回顾已经完成的步骤
    if (stepHistory[step] && step < currentStep) {
      setReviewingStep(step);
      setShowReviewModal(true);
    }
  };

  // 关闭回顾模态框
  const handleCloseReviewModal = () => {
    setShowReviewModal(false);
    setReviewingStep(null);
  };

  // 渲染回顾内容
  const renderReviewContent = () => {
    if (reviewingStep === null || !stepHistory[reviewingStep]) {
      return <Empty description="暂无历史数据" />;
    }

    const stepData = stepHistory[reviewingStep];

    switch (reviewingStep) {
      case 0: // 需求输入
        return (
          <div>
            <Title level={4}>需求输入记录</Title>
            <Paragraph>
              <Text strong>输入时间：</Text>
              {new Date(stepData.timestamp).toLocaleString()}
            </Paragraph>
            <Paragraph>
              <Text strong>需求描述：</Text>
            </Paragraph>
            <Card style={{ marginTop: 16, backgroundColor: '#f5f5f5' }}>
              <Paragraph style={{ whiteSpace: 'pre-wrap', marginBottom: 0 }}>
                {stepData.data.input}
              </Paragraph>
            </Card>
          </div>
        );

      case 1: // 参数确认
        return (
          <div>
            <Title level={4}>参数解析结果</Title>
            <Paragraph>
              <Text strong>解析时间：</Text>
              {new Date(stepData.timestamp).toLocaleString()}
            </Paragraph>
            {stepData.data.parameters && (
              <div style={{ marginTop: 16 }}>
                {renderStructuredParameterTable(stepData.data.parameters)}
              </div>
            )}

            {/* 显示生成的基础配方案例 */}
            {stepData.data.formulas && stepData.data.formulas.length > 0 && (
              <div style={{ marginTop: 24 }}>
                <Title level={5}>生成的基础配方案例</Title>
                <Table
                  dataSource={stepData.data.formulas}
                  rowKey="id"
                  pagination={{ pageSize: 3, showSizeChanger: false }}
                  size="small"
                  scroll={{ x: 800 }}
                  columns={[
                    {
                      title: '配方编号',
                      dataIndex: 'id',
                      key: 'id',
                      width: 100,
                      render: (text) => <Text code>{text}</Text>
                    },
                    {
                      title: '配方名称',
                      dataIndex: 'name',
                      key: 'name',
                      width: 150,
                      render: (text) => <Text strong>{text}</Text>
                    },
                    {
                      title: '溶剂组成',
                      key: 'solvents',
                      width: 200,
                      render: (_, record: any) => (
                        <div>
                          {record.components
                            .filter((c: any) => c.component_type === 'solvent')
                            .map((c: any, idx: number) => (
                              <Tag key={idx} color="blue" style={{ margin: '2px' }}>
                                {c.name} {c.concentration}%
                              </Tag>
                            ))}
                        </div>
                      )
                    },
                    {
                      title: '锂盐',
                      key: 'salt',
                      width: 100,
                      render: (_, record: any) => {
                        const salt = record.components.find((c: any) => c.component_type === 'salt');
                        return salt ? <Tag color="green">{salt.name} {salt.concentration}%</Tag> : '-';
                      }
                    },
                    {
                      title: '添加剂',
                      key: 'additives',
                      width: 180,
                      render: (_, record: any) => (
                        <div>
                          {record.components
                            .filter((c: any) => c.component_type === 'additive')
                            .map((c: any, idx: number) => (
                              <Tag key={idx} color="orange" style={{ margin: '2px' }}>
                                {c.name} {c.concentration}%
                              </Tag>
                            ))}
                        </div>
                      )
                    },
                    {
                      title: '预测能量密度',
                      dataIndex: ['predicted_performance', 'energy_density'],
                      key: 'energy',
                      width: 100,
                      render: (value) => `${value} Wh/kg`
                    },
                    {
                      title: '安全评分',
                      dataIndex: ['predicted_performance', 'safety_score'],
                      key: 'safety',
                      width: 80,
                      render: (value) => {
                        const safetyLevel = Math.round(value * 5);
                        return (
                          <div style={{ textAlign: 'center' }}>
                            <div style={{
                              fontSize: '12px',
                              fontWeight: 'bold',
                              color: safetyLevel >= 4 ? '#52c41a' : safetyLevel >= 3 ? '#faad14' : '#ff4d4f'
                            }}>
                              {safetyLevel}/5
                            </div>
                          </div>
                        );
                      }
                    },
                    {
                      title: '实验批次',
                      dataIndex: ['experimental_data', 'batch_number'],
                      key: 'batch',
                      width: 100,
                      render: (text) => <Text code>{text}</Text>
                    }
                  ]}
                />
              </div>
            )}
          </div>
        );

      case 2: // 数据挖掘
        return (
          <div>
            <Title level={4}>数据挖掘结果</Title>
            <Paragraph>
              <Text strong>挖掘时间：</Text>
              {new Date(stepData.timestamp).toLocaleString()}
            </Paragraph>
            {stepData.data.dataset && (
              <div style={{ marginTop: 16 }}>
                <Row gutter={16}>
                  <Col span={8}>
                    <Card>
                      <Statistic
                        title="原始配方数量"
                        value={stepData.data.dataset.original_formulas?.length || 0}
                        valueStyle={{ color: '#1890ff' }}
                      />
                    </Card>
                  </Col>
                  <Col span={8}>
                    <Card>
                      <Statistic
                        title="扩增配方数量"
                        value={stepData.data.dataset.augmented_formulas?.length || 0}
                        valueStyle={{ color: '#52c41a' }}
                      />
                    </Card>
                  </Col>
                  <Col span={8}>
                    <Card>
                      <Statistic
                        title="扩增率"
                        value={stepData.data.dataset.original_formulas?.length > 0 ?
                          Math.round((stepData.data.dataset.augmented_formulas.length / stepData.data.dataset.original_formulas.length) * 100) : 0}
                        suffix="%"
                        valueStyle={{ color: '#722ed1' }}
                      />
                    </Card>
                  </Col>
                </Row>
              </div>
            )}
