        );

      case 3: // 性质预测
        return (
          <div>
            <Title level={4}>性质预测结果</Title>
            <Paragraph>
              <Text strong>预测时间：</Text>
              {new Date(stepData.timestamp).toLocaleString()}
            </Paragraph>

            {/* 预测概览 */}
            <Card size="small" style={{ marginTop: 16 }}>
              <Row gutter={8}>
                <Col span={6}>
                  <Statistic
                    title="总预测数"
                    value={stepData.data.total_predictions || 0}
                    suffix="个"
                    valueStyle={{ fontSize: '14px', color: '#1890ff' }}
                  />
                </Col>
                <Col span={6}>
                  <Statistic
                    title="筛选数量"
                    value={stepData.data.selected_count || 0}
                    suffix="个"
                    valueStyle={{ fontSize: '14px', color: '#52c41a' }}
                  />
                </Col>
                <Col span={6}>
                  <Statistic
                    title="筛选率"
                    value={stepData.data.total_predictions > 0 ?
                      Math.round((stepData.data.selected_count / stepData.data.total_predictions) * 100) : 0}
                    suffix="%"
                    valueStyle={{ fontSize: '14px', color: '#fa8c16' }}
                  />
                </Col>
                <Col span={6}>
                  <Statistic
                    title="模型"
                    value={stepData.data.model_info?.model_type?.slice(0, 8) || 'UniMol'}
                    valueStyle={{ fontSize: '12px' }}
                  />
                </Col>
              </Row>
            </Card>

            {/* 优质分子预览 */}
            {stepData.data.predicted_formulas && stepData.data.predicted_formulas.length > 0 && (
              <div style={{ marginTop: 16 }}>
                <Title level={5}>筛选出的优质分子（前3名）</Title>
                <Table
                  dataSource={stepData.data.predicted_formulas.slice(0, 3)}
                  rowKey="formula_index"
                  pagination={false}
                  size="small"
                  columns={[
                    {
                      title: '排名',
                      dataIndex: 'formula_index',
                      key: 'rank',
                      width: 50,
                      render: (text) => (
                        <Badge count={text} style={{ backgroundColor: '#52c41a' }} />
                      )
                    },
                    {
                      title: '配方',
                      dataIndex: ['formula', 'name'],
                      key: 'name',
                      ellipsis: true
                    },
                    {
                      title: '评分',
                      dataIndex: 'overall_score',
                      key: 'score',
                      width: 60,
                      render: (score) => (
                        <Text strong style={{ color: score > 0.85 ? '#52c41a' : '#1890ff' }}>
                          {Math.round(score * 100)}
                        </Text>
                      )
                    },
                    {
                      title: '能量密度',
                      dataIndex: ['system_properties', 'energy_density'],
                      key: 'energy',
                      width: 70,
                      render: (value) => `${Math.round(value)}`
                    }
                  ]}
                />
                {stepData.data.predicted_formulas.length > 3 && (
                  <Text type="secondary" style={{ fontSize: '12px' }}>
                    还有 {stepData.data.predicted_formulas.length - 3} 个分子...
                  </Text>
                )}
              </div>
            )}
          </div>
        );

      case 4: // 配方生成
        return (
          <div>
            <Title level={4}>最终配方生成</Title>
            <Paragraph>
              <Text strong>生成时间：</Text>
              {new Date(stepData.timestamp).toLocaleString()}
            </Paragraph>
            {stepData.data.formula && (
              <div style={{ marginTop: 16 }}>
                <Alert
                  message="配方生成成功"
                  description={`已生成最优配方，包含 ${stepData.data.formula.components?.length || 0} 个组分。`}
                  type="success"
                  showIcon
                />
                {renderFormulaComponents()}
              </div>
            )}
          </div>
        );

      default:
        return <Empty description="暂无历史数据" />;
    }
  };

  // 步骤定义
  const steps = [
    {
      title: '需求输入',
      description: '输入自然语言需求',
      icon: <ExperimentOutlined />
    },
    {
      title: '参数确认',
      description: '确认提取的参数',
      icon: <CheckCircleOutlined />
    },
    {
      title: '数据挖掘',
      description: '文献挖掘与数据扩增',
      icon: <ClockCircleOutlined />
    },
    {
      title: '性质预测',
      description: '高通量性质预测',
      icon: <ClockCircleOutlined />
    },
    {
      title: '配方生成',
      description: '生成实验配方',
      icon: <PlayCircleOutlined />
    }
  ];

  // 1. 解析用户需求
  const handleParseRequest = async (values: { input: string }) => {
    // 首先进行语义验证
    const validation = validateInputSemantic(values.input);
    console.log('语义验证结果:', validation);

    if (!validation.isValid) {
      message.error(validation.reason || '输入内容无效，请描述具体的电池需求');
      return;
    }

    setLoading(true);
    setIsParsing(true);

    // 重置进度条
    setParsingProgress(prev => ({
      ...prev,
      currentStep: 0,
      steps: prev.steps.map(step => ({ ...step, completed: false }))
    }));

    try {
      console.log('开始解析用户需求:', values.input);

      // 模拟解析过程，逐步更新进度条
      const steps = [
        { step: 0, delay: 600, message: '正在解析自然语言...' },
        { step: 1, delay: 800, message: '正在提取性能参数...' },
        { step: 2, delay: 700, message: '正在识别电池系统类型...' },
        { step: 3, delay: 900, message: '正在分析应用场景...' },
        { step: 4, delay: 500, message: '正在整理结构化数据...' }
      ];

      for (const { step, delay, message } of steps) {
        await new Promise(resolve => setTimeout(resolve, delay));
        setParsingProgress(prev => ({
          currentStep: step + 1,
          steps: prev.steps.map((stepItem, index) => ({
            ...stepItem,
            completed: index <= step
          }))
        }));
      }

      // 调用API进行解析
      const response = await aiDesignerApi.parseRequest(values);
      console.log('API响应:', response);

      if (response.success && response.data) {
        console.log('解析成功，数据:', response.data);

        // 保存解析结果
        setParsedParameters(response.data);
        setEditableParameters(safeJSONParse(JSON.stringify(response.data), response.data));

        // 确保状态更新
        setTimeout(() => {
          console.log('设置currentStep为1，当前parsedParameters:', response.data);
          setCurrentStep(1);
          console.log('currentStep已设置为1');

          // 验证状态是否正确设置
          setTimeout(() => {
            console.log('验证currentStep:', 1);
          }, 100);
        }, 0);

        // 保存历史记录
        setUserInput(values.input);
        console.log('userInput已设置:', values.input);
        setStepHistory(prev => ({
          ...prev,
          0: {
            type: 'input',
            title: '需求输入',
            timestamp: new Date().toISOString(),
            data: { input: values.input, success: true }
          }
        }));

        message.success('需求解析完成！已识别' +
          (response.data.basic_info?.system_type?.label || '') +
          '类型电池系统');
      } else {
        console.error('API解析失败:', response);
        // API失败时提供fallback数据，确保界面可以继续工作
        const fallbackData = createFallbackParsedData(values.input);
        setParsedParameters(fallbackData);
        setEditableParameters(fallbackData);
        setCurrentStep(1);
        setUserInput(values.input);

        message.warning('后端服务暂时不可用，已使用基础解析继续流程');
      }
    } catch (error) {
      console.error('解析请求出错:', error);

      // 记录错误信息用于分析
      const errorInfo = {
        timestamp: new Date().toISOString(),
        userInput: values.input,
        error: error.message || error,
        stack: error.stack,
        type: 'parse_request_error'
      };

      // 保存到localStorage用于调试（可选）
      try {
        const errorHistory = JSON.parse(localStorage.getItem('parse_error_history') || '[]');
        errorHistory.push(errorInfo);
        // 只保留最近10条错误记录
        if (errorHistory.length > 10) {
          errorHistory.shift();
        }
        localStorage.setItem('parse_error_history', JSON.stringify(errorHistory));
      } catch (e) {
        console.warn('无法保存错误历史:', e);
      }

      // 网络错误或API不可用时也提供fallback
      const fallbackData = createFallbackParsedData(values.input);
      setParsedParameters(fallbackData);
      setEditableParameters(fallbackData);
      setCurrentStep(1);
      setUserInput(values.input);

      // 根据错误类型显示不同的提示信息
      let errorMessage = '网络连接失败，已使用基础解析继续流程';
      let errorLevel = 'warning'; // warning, error, info

      // 详细错误分类
      if (error.code === 'ECONNABORTED' || error.message?.includes('超时')) {
        errorMessage = 'LLM服务响应超时，已使用基础解析继续流程。功能正常，但解析精度可能略有下降。';
        errorLevel = 'warning';
      } else if (error.message?.includes('网络连接失败') || error.message?.includes('无法连接到LLM服务')) {
        errorMessage = 'LLM服务网络连接失败，已使用基础解析继续流程。请检查网络连接后重试。';
        errorLevel = 'warning';
      } else if (error.message?.includes('服务器内部错误')) {
        errorMessage = 'LLM服务暂时不可用，已使用基础解析继续流程。功能正常，但解析精度可能略有下降。';
        errorLevel = 'warning';
      } else if (error.message?.includes('服务暂时不可用')) {
        errorMessage = 'LLM服务维护中，已使用基础解析继续流程。功能正常，但解析精度可能略有下降。';
        errorLevel = 'info';
      } else if (error.response?.status === 401) {
        errorMessage = 'API认证失败，已使用基础解析继续流程。请联系管理员。';
        errorLevel = 'error';
      } else if (error.response?.status === 403) {
        errorMessage = 'API访问权限不足，已使用基础解析继续流程。请联系管理员。';
        errorLevel = 'error';
      } else if (error.response?.status === 429) {
        errorMessage = 'API请求频率过高，已使用基础解析继续流程。请稍后重试。';
        errorLevel = 'warning';
      } else if (error.response?.status >= 500) {
        errorMessage = 'LLM服务器错误，已使用基础解析继续流程。功能正常，但解析精度可能略有下降。';
        errorLevel = 'warning';
      } else {
        errorMessage = '解析服务异常，已使用基础解析继续流程。功能正常，但解析精度可能略有下降。';
        errorLevel = 'warning';
      }

      // 根据错误级别显示不同类型的消息
      if (errorLevel === 'error') {
        message.error(errorMessage);
      } else if (errorLevel === 'info') {
        message.info(errorMessage);
      } else {
        message.warning(errorMessage);
      }

      // 提供重试选项（对于网络相关的错误）
      if (error.code === 'ECONNABORTED' ||
          error.message?.includes('网络连接失败') ||
          error.message?.includes('无法连接')) {

        // 延迟显示重试选项
        setTimeout(() => {
          Modal.info({
            title: '网络连接提示',
            content: (
              <div>
                <p>检测到网络连接问题，您可以：</p>
                <ul>
                  <li>检查网络连接是否正常</li>
                  <li>稍后重试以获得更准确的AI解析结果</li>
                  <li>继续使用当前基础解析结果</li>
                </ul>
                <p>基础解析已根据您的输入进行了智能分析，可以正常使用后续功能。</p>
              </div>
            ),
            okText: '我知道了'
          });
        }, 1000);
      }
    } finally {
      setLoading(false);
      setIsParsing(false);
    }
  };

  // 2. 确认参数
  const handleConfirmParameters = async () => {
    if (!editableParameters) return;

    setLoading(true);
    try {
      const systemType = editableParameters.basic_info.system_type;

      // 构建确认的参数，包含正负极材料信息
      const confirmed = {
        system_type: systemType.value || '全电池',
        system_type_info: {
          label: systemType.label || '全电池系统',
          material_name: systemType.material_name || '',
          both_materials: systemType.both_materials || {
            positive: '',
            negative: ''
          }
        },
        application_scenario: editableParameters.basic_info.application_scenario.value || '3C',
        performance_requirements: {
          energy_density: editableParameters.performance_params.energy_density.value,
          power_density: editableParameters.performance_params.power_density.value,
          cycle_life: editableParameters.performance_params.cycle_life.value,
          working_temperature: editableParameters.performance_params.working_temperature.value,
          safety: editableParameters.performance_params.safety.value
        }
      };

      console.log('确认的参数:', confirmed);

      try {
        const response = await aiDesignerApi.confirmParameters({ parameters: confirmed });
        if (response.success) {
          setConfirmedParameters(confirmed);
        } else {
          console.warn('参数确认API失败，使用本地确认');
          setConfirmedParameters(confirmed);
        }
      } catch (error) {
        console.warn('参数确认API不可用，使用本地确认');
        setConfirmedParameters(confirmed);
      }

      // 无论API是否成功，都继续下一步
      const baseFormulas = generateBaseFormulas(
        confirmed.system_type,
        confirmed.application_scenario,
        confirmed.system_type_info
      );

      // 保存步骤历史
      setStepHistory(prev => ({
        ...prev,
        1: {
          title: '参数确认',
          description: '确认提取的电池性能参数并生成基础配方案例',
          timestamp: new Date().toISOString(),
          data: {
            parameters: editableParameters,
            formulas: baseFormulas
          },
          input: { confirmed }
        }
      }));

      setCurrentStep(2);
      message.success('参数确认完成！正负极材料信息已保存。');
    } catch (error) {
      console.error('参数确认错误:', error);
      message.error('参数确认失败，请重试');
    } finally {
      setLoading(false);
    }
  };

  // 更新参数值
  const updateParameterValue = (category: string, paramKey: string, newValue: any) => {
    if (!editableParameters) return;

    const updatedParams = safeJSONParse(JSON.stringify(editableParameters), editableParameters); // 深拷贝

    if (category === 'basic_info') {
      if (paramKey === 'system_type') {
        // 处理system_type的特殊情况，直接替换整个对象
        updatedParams.basic_info.system_type = newValue;
      } else {
        (updatedParams.basic_info as Record<string, any>)[paramKey].value = newValue;
      }
    } else if (category === 'performance_params') {
      (updatedParams.performance_params as Record<string, any>)[paramKey].value = newValue;
    }

    setEditableParameters(updatedParams);
  };

  // 检查是否有空的必填字段
  const hasEmptyRequiredFields = () => {
    if (!editableParameters) return true;

    // 检查电极材料是否为空（现在正负极都是必填的）
    const systemType = editableParameters.basic_info.system_type;
    if (systemType?.both_materials) {
      const positiveEmpty = !systemType.both_materials.positive || systemType.both_materials.positive.trim() === '';
      const negativeEmpty = !systemType.both_materials.negative || systemType.both_materials.negative.trim() === '';
      if (positiveEmpty || negativeEmpty) {
        return true;
      }
    } else {
      // 如果没有both_materials结构，也返回true（需要用户输入）
      return true;
    }

    // 检查其他必填的性能参数
    const requiredFields = [
      editableParameters.performance_params.energy_density,
      editableParameters.performance_params.power_density,
      editableParameters.performance_params.cycle_life,
      editableParameters.performance_params.working_temperature,
      editableParameters.performance_params.safety
    ];

    return requiredFields.some(field =>
      field.required && (
        field.value === null ||
        field.value === undefined ||
        field.value === '' ||
        (typeof field.value === 'number' && isNaN(field.value))
      )
    );
  };

  // 3.1 处理文献
  const handleProcessLiterature = async () => {
    if (!confirmedParameters) {
      message.error('没有确认的参数，请先完成参数确认步骤');
      return;
    }

    setLoading(true);
    setLiteratureData([]);

    try {
      message.loading('正在处理文献数据...', 0);

      const processResponse = await literatureApi.processLiterature({
        key_parameters: confirmedParameters,
        batch_size: 10
      });

      message.destroy();

      if (processResponse.success && processResponse.data) {
        const literatureResults = processResponse.data.results;
        // 使用实际返回的文献数据
        if (literatureResults && literatureResults.literature_data) {
          setLiteratureData(literatureResults.literature_data);
        } else {
          setLiteratureData([]);
        }

        message.success(`文献处理完成！处理了 ${literatureResults?.successful || 0} 篇文献`);
      } else {
        // 使用模拟数据
        const mockLiteratureData = Array.from({ length: 5 }, (_, i) => ({
          id: i + 1,
          title: `电解液相关研究论文_${i + 1}`,
          authors: ["研究者A", "研究者B", "研究者C"],
          journal: "电池技术学报",
          year: 2020 + i,
          doi: `10.1234/battery.${2023 + i}.${i + 1}`,
          abstract: "本文研究了新型电解液配方的性能...",
          key_findings: [
            "高电导率电解液配方",
            "优异的循环稳定性",
            "良好的安全性能"
          ],
          relevance_score: 0.8 + Math.random() * 0.15,
          extracted_molecules: [
            {
              name: i === 0 ? "EC" : i === 1 ? "DMC" : i === 2 ? "LiPF6" : i === 3 ? "VC" : "FEC",
              component_type: i <= 1 ? "solvent" : i <= 2 ? "salt" : "additive",
              chemical_formula: i <= 1 ? `C${3+i}H${4+i}O3` : i === 2 ? "LiPF6" : "C3H4O3",
              predicted_properties: {
                conductivity: 8 + Math.random() * 4,
                viscosity: 2 + Math.random() * 2,
                sei_formation_ability: Math.random(),
                flame_retardancy: Math.random()
              },
              source_papers: [i + 1],
              prediction_confidence: 0.75 + Math.random() * 0.2
            }
          ]
        }));

        setLiteratureData(mockLiteratureData);
        message.success('文献处理完成（使用模拟数据）');
      }
    } catch (error) {
      console.error('文献处理失败:', error);
      message.error('文献处理失败，请重试');
    } finally {
      setLoading(false);
    }
  };

  // 3.2 生成新分子
  const handleGenerateMolecules = async () => {
    if (literatureData.length === 0) {
      message.error('请先完成文献处理');
      return;
    }

    setLoading(true);

    try {
      message.loading('正在生成新分子...', 0);

      // 基于文献数据生成分子
      const literatureResults = {
        papers_found: literatureData.length,
        molecules_identified: literatureData.reduce((sum, lit) => sum + (lit.extracted_molecules?.length || 0), 0),
        generated_molecules: []
      };

      // 添加从文献中提取的分子
      literatureData.forEach(lit => {
        if (lit.extracted_molecules) {
          literatureResults.generated_molecules.push(...lit.extracted_molecules);
        }
      });

      // 生成新的分子
      const generateResponse = await molecularApi.generateMolecules({
        literature_results: literatureResults,
        target_count: 12,
        component_types: ['solvent', 'salt', 'additive']
      });

      message.destroy();

      if (generateResponse.success && generateResponse.data?.molecules) {
        setGeneratedMolecules(generateResponse.data.molecules);
        message.success(`分子生成完成！生成了 ${generateResponse.data.molecules.length} 个新分子`);
      } else {
        // 使用模拟数据
        const mockMolecules = [
          // 溶剂分子
          { name: "EC", component_type: "solvent", chemical_formula: "C3H4O3", prediction_confidence: 0.85 },
          { name: "DMC", component_type: "solvent", chemical_formula: "C3H6O3", prediction_confidence: 0.88 },
          { name: "EMC", component_type: "solvent", chemical_formula: "C4H8O3", prediction_confidence: 0.82 },
          { name: "PC", component_type: "solvent", chemical_formula: "C4H6O3", prediction_confidence: 0.80 },

          // 锂盐分子
          { name: "LiPF6", component_type: "salt", chemical_formula: "LiPF6", prediction_confidence: 0.95 },
          { name: "LiFSI", component_type: "salt", chemical_formula: "LiFSI", prediction_confidence: 0.87 },
          { name: "LiTFSI", component_type: "salt", chemical_formula: "LiTFSI", prediction_confidence: 0.83 },

          // 添加剂分子
          { name: "VC", component_type: "additive", chemical_formula: "C3H4O3", prediction_confidence: 0.90 },
          { name: "FEC", component_type: "additive", chemical_formula: "C3H4O3", prediction_confidence: 0.88 },
          { name: "PS", component_type: "additive", chemical_formula: "C8H8O3", prediction_confidence: 0.79 },
          { name: "DTD", component_type: "additive", chemical_formula: "C4H6O3S2", prediction_confidence: 0.81 },
          { name: "VEC", component_type: "additive", chemical_formula: "C5H8O3", prediction_confidence: 0.77 }
        ];

        setGeneratedMolecules(mockMolecules);
        message.success(`分子生成完成（使用模拟数据）！生成了 ${mockMolecules.length} 个分子`);
      }
    } catch (error) {
      console.error('分子生成失败:', error);
      message.error('分子生成失败，请重试');
    } finally {
      setLoading(false);
    }
  };

  // 3. 数据挖掘
  const handleMineData = async () => {
    if (!confirmedParameters) return;

    setLoading(true);
    setMiningProgress(0);
    setMiningStatus('开始数据挖掘...');
    setGeneratedMolecules([]);
    setLiteratureData([]);

    try {
      let literatureResults = null;

      // 步骤1: 文献挖掘 (使用关键参数作为输入)
      setMiningStatus('正在进行文献挖掘，基于关键参数...');
      setMiningProgress(25);

