    const components = formula.components || [];
    const solventData: { name: string; value: number }[] = [];
    const saltData: { name: string; value: number }[] = [];
    const additiveData: { name: string; value: number }[] = [];

    components.forEach((comp: any) => {
      const name = comp.name || '未知';
      const concentration = parseFloat(comp.concentration) || 0;

      if (comp.component_type === '溶剂' || name.includes('溶剂') || name.includes('EC') || name.includes('DMC') || name.includes('EMC')) {
        solventData.push({ name, value: concentration });
      } else if (comp.component_type === '盐' || name.includes('盐') || name.includes('LiPF6') || name.includes('LiTFSI')) {
        saltData.push({ name, value: concentration });
      } else if (comp.component_type === '添加剂' || name.includes('添加剂') || name.includes('VC') || name.includes('FEC')) {
        additiveData.push({ name, value: concentration });
      }
    });

    return { solventData, saltData, additiveData };
