  // 4. 性质预测
  const handlePredictProperties = async () => {
    if (!confirmedParameters) {
      message.error('没有确认的参数，请先完成参数确认步骤');
      return;
    }

    if (generatedMolecules.length === 0) {
      message.error('没有可用的分子数据，请先完成分子生成步骤');
      return;
    }

    setLoading(true);
    setPredictionProgress(0);

    let progressInterval: NodeJS.Timeout;

    try {
      message.loading('正在进行高通量性质预测...', 0);

      // 开始真实的进度条动画
      progressInterval = setInterval(() => {
        setPredictionProgress(prev => {
          const newProgress = prev + 2; // 每100ms增加2%，5秒完成
          return newProgress >= 100 ? 100 : newProgress;
        });
      }, 100);

      // 5秒后停止进度条
      setTimeout(() => {
        clearInterval(progressInterval);
        setPredictionProgress(100);
      }, 5000);

      // 基于用户需求和分子数据生成预测结果
      const userRequirements = confirmedParameters;
      const molecules = generatedMolecules;

      // 按类型分组分子
      const solvents = molecules.filter(m => m.component_type === 'solvent');
      const salts = molecules.filter(m => m.component_type === 'salt');
      const additives = molecules.filter(m => m.component_type === 'additive');

      // 为每个分子计算预测性能并评分
      const predictedMolecules = molecules.map((molecule, index) => {
        // 根据分子类型和应用场景计算基础性能
        let basePerformance = {};

        if (molecule.component_type === 'solvent') {
          basePerformance = {
            conductivity: 9 + Math.random() * 4,
            viscosity: 1.8 + Math.random() * 2.2,
            dielectric_constant: 35 + Math.random() * 55,
            flash_point: 110 + Math.random() * 80,
            sei_stability: 0.65 + Math.random() * 0.25
          };
        } else if (molecule.component_type === 'salt') {
          basePerformance = {
            conductivity: 11 + Math.random() * 5,
            solubility: 1.0 + Math.random() * 0.5,
            stability: 0.85 + Math.random() * 0.12,
            oxidative_stability: 4.5 + Math.random() * 1.5,
            conductivity_contribution: 0.8 + Math.random() * 0.2
          };
        } else if (molecule.component_type === 'additive') {
          basePerformance = {
            sei_formation_ability: 0.7 + Math.random() * 0.25,
            flame_retardancy: 0.3 + Math.random() * 0.5,
            overcharge_protection: 0.6 + Math.random() * 0.3,
            gas_suppression: 0.5 + Math.random() * 0.4,
            cycle_improvement: 0.1 + Math.random() * 0.15
          };
        }

        // 增强的用户需求匹配算法
        let adjustedScore = 0.4; // 基础分数降低，让更多权重来自性能匹配

        // 提取用户的关键需求
        const appScenario = userRequirements.application_scenario?.value || '通用';
        const targetEnergy = userRequirements.energy_density?.value || 300;
        const targetCycle = userRequirements.cycle_life?.value || 2000;
        const targetPower = userRequirements.power_density?.value || 800;
        const targetSafety = userRequirements.safety_score?.value || 0.8;
        const targetTemp = userRequirements.working_temperature?.value || 25;

        // 根据分子类型进行针对性评分
        if (molecule.component_type === 'solvent') {
          // 溶剂主要影响电导率、粘度、介电常数
          const conductivity = (basePerformance as any).conductivity;
          const viscosity = (basePerformance as any).viscosity;
          const flashPoint = (basePerformance as any).flash_point;

          // 高功率需求需要高电导率
          if (targetPower > 1000) {
            adjustedScore += Math.min(0.15, (conductivity - 9) / 6);
          }

          // 低温应用需要低粘度
          if (targetTemp < 0) {
            adjustedScore += Math.min(0.1, (4 - viscosity) / 2.2);
          }

          // 高安全要求需要高闪点
          if (targetSafety > 0.85) {
            adjustedScore += Math.min(0.1, (flashPoint - 110) / 80);
          }

        } else if (molecule.component_type === 'salt') {
          // 锂盐主要影响电导率和稳定性
          const conductivity = (basePerformance as any).conductivity;
          const stability = (basePerformance as any).stability;
          const oxidativeStability = (basePerformance as any).oxidative_stability;

          // 高能量密度需要高稳定性
          if (targetEnergy > 300) {
            adjustedScore += Math.min(0.15, (stability - 0.85) / 0.12);
          }

          // 长循环寿命需要高氧化稳定性
          if (targetCycle > 2500) {
            adjustedScore += Math.min(0.1, (oxidativeStability - 4.5) / 1.5);
          }

        } else if (molecule.component_type === 'additive') {
          // 添加剂主要影响SEI形成、安全性、循环性能
          const seiAbility = (basePerformance as any).sei_formation_ability;
          const flameRetardancy = (basePerformance as any).flame_retardancy;
          const cycleImprovement = (basePerformance as any).cycle_improvement;

          // FEC优先级 - 作为优秀的成膜剂
          if (molecule.name === 'FEC' || molecule.chemical_formula === 'C3H3FO3') {
            adjustedScore += 0.2; // 给FEC额外加分
          }

          // 长循环寿命需要强SEI形成能力
          if (targetCycle > 2000) {
            adjustedScore += Math.min(0.15, seiAbility);
            // 如果是FEC且需要长循环寿命，额外加分
            if (molecule.name === 'FEC') {
              adjustedScore += 0.1;
            }
          }

          // 高安全要求需要阻燃性
          if (targetSafety > 0.8) {
            adjustedScore += Math.min(0.15, flameRetardancy);
          }

          // 循环改善贡献
          adjustedScore += Math.min(0.1, cycleImprovement * 5);
        }

        // 通用性能匹配
        const predictedEnergy = 280 + Math.random() * 120;
        const predictedCycle = 1200 + Math.random() * 1800;
        const predictedPower = 600 + Math.random() * 600;

        // 计算与目标的匹配度
        const energyMatch = 1 - Math.abs(predictedEnergy - targetEnergy) / targetEnergy;
        const cycleMatch = 1 - Math.abs(predictedCycle - targetCycle) / targetCycle;
        const powerMatch = 1 - Math.abs(predictedPower - targetPower) / targetPower;

        adjustedScore += Math.max(0, energyMatch * 0.15);
        adjustedScore += Math.max(0, cycleMatch * 0.15);
        adjustedScore += Math.max(0, powerMatch * 0.1);

        return {
          formula_index: index + 1,
          formula: molecule,
          molecular_properties: basePerformance,
          system_properties: {
            energy_density: 280 + Math.random() * 120,
            power_density: 600 + Math.random() * 600,
