          overall_score: Math.min(0.95, adjustedScore + Math.random() * 0.2),
          prediction_confidence: molecule.prediction_confidence || (0.75 + Math.random() * 0.2)
        };
      });

      // 按综合评分排序，筛选最优分子
      const sortedMolecules = predictedMolecules.sort((a, b) => b.overall_score - a.overall_score);
      const topMolecules = sortedMolecules.slice(0, Math.min(20, sortedMolecules.length));

      // 构建预测数据
      const predictedData = {
