                  flash_point: 100 + Math.random() * 50
                }
              }
            })),
          top_salts: topMolecules
            .filter(m => m && m.formula && m.formula.component_type === 'salt')
            .slice(0, 3)
            .map(m => ({
              ...m,
              formula: {
