        message.error('分子数据结构不完整，无法生成配方');
        return;
      }

      // 选择最优的分子组合
      console.log('选择最优分子:');
      bestSolvent = validSolvents[0].formula;
      console.log('bestSolvent:', bestSolvent);
      bestSalt = validSalts[0].formula;
      console.log('bestSalt:', bestSalt);
      bestAdditive = validAdditives.length > 0 ? validAdditives[0].formula : null;
      console.log('bestAdditive:', bestAdditive);

      // 提取用户需求参数
      const targetEnergy = confirmedParameters?.performance_requirements?.energy_density || 300;
      const targetPower = confirmedParameters?.performance_requirements?.power_density || 800;
      const targetCycle = confirmedParameters?.performance_requirements?.cycle_life || 2000;
      const targetSafety = confirmedParameters?.performance_requirements?.safety || 0.8;
      const appScenario = confirmedParameters?.application_scenario || '动力电池';

      // 智能配比计算函数
      const calculateOptimalProportions = () => {
        let solventRatio = 0; // 主溶剂比例
        let secondarySolventRatio = 0; // 辅助溶剂比例
        let saltRatio = 0; // 锂盐比例
        let additiveRatio = 0; // 添加剂比例

        // 根据应用场景调整基础配比
        if (appScenario === '动力电池') {
          // 动力电池：高能量密度，需要较高锂盐浓度
          solventRatio = 35 + Math.random() * 10; // 35-45%
          secondarySolventRatio = 20 + Math.random() * 10; // 20-30%
          saltRatio = 12 + Math.random() * 3; // 12-15%
          additiveRatio = 2 + Math.random() * 3; // 2-5%
        } else if (appScenario === '储能') {
          // 储能：长循环寿命，适中锂盐浓度
          solventRatio = 40 + Math.random() * 10; // 40-50%
          secondarySolventRatio = 25 + Math.random() * 5; // 25-30%
          saltRatio = 10 + Math.random() * 2; // 10-12%
          additiveRatio = 3 + Math.random() * 2; // 3-5%
        } else if (appScenario === '3C') {
          // 3C产品：高功率密度，低粘度
          solventRatio = 30 + Math.random() * 10; // 30-40%
          secondarySolventRatio = 30 + Math.random() * 10; // 30-40%
          saltRatio = 8 + Math.random() * 2; // 8-10%
          additiveRatio = 2 + Math.random() * 2; // 2-4%
        } else {
          // 通用配方
          solventRatio = 35 + Math.random() * 10;
          secondarySolventRatio = 25 + Math.random() * 10;
          saltRatio = 10 + Math.random() * 3;
          additiveRatio = 2 + Math.random() * 3;
        }

        // 根据具体需求进一步调整
        if (targetEnergy > 350) {
          // 高能量密度：增加锂盐浓度
          saltRatio += Math.min(3, saltRatio * 0.2);
          solventRatio -= saltRatio * 0.5;
        }

        if (targetPower > 1200) {
          // 高功率密度：降低粘度，增加低粘度溶剂比例
          secondarySolventRatio += 5;
          solventRatio -= 3;
        }

        if (targetCycle > 3000) {
          // 长循环寿命：增加添加剂比例
          additiveRatio += Math.min(2, additiveRatio * 0.5);
          saltRatio -= additiveRatio * 0.5;
        }

        if (targetSafety > 0.9) {
          // 高安全性：增加阻燃添加剂
          additiveRatio += Math.min(3, additiveRatio * 0.8);
          solventRatio -= additiveRatio * 0.3;
        }

        // 标准化比例，确保总和为100%
        const total = solventRatio + secondarySolventRatio + saltRatio + additiveRatio;
        const normalizedRatio = 100 / total;

        return {
          mainSolvent: Math.round(solventRatio * normalizedRatio),
          secondarySolvent: Math.round(secondarySolventRatio * normalizedRatio),
          salt: Math.round(saltRatio * normalizedRatio),
          additive: Math.round(additiveRatio * normalizedRatio)
        };
      };

      const proportions = calculateOptimalProportions();

