                  进入性质预测
                </Button>
              </Space>
            </div>
          </div>
        )}

        {currentStep === 3 && (
          <div>
            {(() => {
              console.log('步骤3界面渲染:', { currentStep, predictedData: !!predictedData, predictedDataLength: predictedData?.predicted_formulas?.length });
