                                类型: {property.type || 'N/A'}
                              </div>
                              <div style={{ fontSize: '12px', color: '#666' }}>
                                数值: {property.value || 'N/A'} {property.unit || ''}
                              </div>
                              {property.conditions && (
                                <div style={{ fontSize: '12px', color: '#666' }}>
                                  条件: {property.conditions}
                                </div>
                              )}
                            </Card>
                          </List.Item>
                        )}
                      />
                    </TabPane>
                  )}
                </Tabs>
              </div>
            )}

            {selectedLiterature.processing_log && (
              <div style={{ marginTop: 24 }}>
                <Title level={5}>处理日志</Title>
                <pre style={{ background: '#f5f5f5', padding: '12px', borderRadius: '4px', fontSize: '12px', maxHeight: '200px', overflow: 'auto' }}>
                  {selectedLiterature.processing_log}
                </pre>
              </div>
            )}
          </div>
        )}
      </Modal>


      {/* 文献挖掘完整界面模态框 - 已移除，直接显示在主界面中 */}
      {/*
      <Modal
        title={
          <span>
            <FileTextOutlined style={{ marginRight: 8, color: '#1890ff' }} />
            文献挖掘与管理系统
          </span>
        }
        open={showLiteratureInterface}
        onCancel={() => setShowLiteratureInterface(false)}
        footer={[
          <Button key="close" onClick={() => setShowLiteratureInterface(false)}>
            关闭
          </Button>
        ]}
        width={1200}
        style={{ top: 20 }}
        destroyOnClose
      >
        <div style={{ maxHeight: '70vh', overflow: 'auto' }}>
          <LiteraturePage />
        </div>
      </Modal>
      */}

      {/* 步骤回顾模态框 */}
      <Modal
        title={
          <span>
            <span style={{ marginRight: 8 }}>{steps[reviewingStep || 0]?.icon}</span>
            {steps[reviewingStep || 0]?.title} - 历史回顾
          </span>
        }
        open={showReviewModal}
        onCancel={handleCloseReviewModal}
        footer={[
          <Button key="close" onClick={handleCloseReviewModal}>
            关闭
          </Button>
        ]}
        width={800}
        style={{ top: 20 }}
      >
        {renderReviewContent()}
      </Modal>
    </div>
  );
};

export default AIDesignerPage;
